const hre = require("hardhat");
const { ethers } = hre;
const { deployGovernedSystem } = require("./lib/deployment/deployGovernedSystem");
const { ROLE_IDS, WAD } = require("./lib/config/marketConfig");
(async () => {
  const [deployer] = await ethers.getSigners();
  const deployment = await deployGovernedSystem({
    governanceTokenSupply: 1000000n * WAD,
    votingDelaySeconds: 1,
    votingPeriodSeconds: 300,
    timelockMinDelaySeconds: 60,
    quorumNumerator: 4,
  });
  const accessManager = deployment.contracts.accessManager;
  const timelock = deployment.governanceRoot.timelock;
  const governor = deployment.governanceRoot.governor;
  const timelockAddress = await timelock.getAddress();
  const TIMELOCK_ADMIN_ROLE = await timelock.DEFAULT_ADMIN_ROLE();
  const PROPOSER_ROLE = await timelock.PROPOSER_ROLE();
  const checks = {
    deployer: deployer.address,
    timelock: timelockAddress,
    governor: await governor.getAddress(),
    accessManagerAdmin: {
      deployer: (await accessManager.hasRole(0, deployer.address))[0],
      timelock: (await accessManager.hasRole(0, timelockAddress))[0],
    },
    privilegedRoles: {
      emergency: {
        deployer: (await accessManager.hasRole(ROLE_IDS.EMERGENCY, deployer.address))[0],
        timelock: (await accessManager.hasRole(ROLE_IDS.EMERGENCY, timelockAddress))[0],
      },
      riskAdmin: {
        deployer: (await accessManager.hasRole(ROLE_IDS.RISK_ADMIN, deployer.address))[0],
        timelock: (await accessManager.hasRole(ROLE_IDS.RISK_ADMIN, timelockAddress))[0],
      },
      treasury: {
        deployer: (await accessManager.hasRole(ROLE_IDS.TREASURY, deployer.address))[0],
        timelock: (await accessManager.hasRole(ROLE_IDS.TREASURY, timelockAddress))[0],
      },
      minter: {
        deployer: (await accessManager.hasRole(ROLE_IDS.MINTER, deployer.address))[0],
        timelock: (await accessManager.hasRole(ROLE_IDS.MINTER, timelockAddress))[0],
      },
      governance: {
        deployer: (await accessManager.hasRole(ROLE_IDS.GOVERNANCE, deployer.address))[0],
        timelock: (await accessManager.hasRole(ROLE_IDS.GOVERNANCE, timelockAddress))[0],
      }
    },
    timelockRoles: {
      defaultAdminDeployer: await timelock.hasRole(TIMELOCK_ADMIN_ROLE, deployer.address),
      proposerGovernor: await timelock.hasRole(PROPOSER_ROLE, await governor.getAddress()),
    },
  };
  console.log(JSON.stringify(checks, null, 2));
  process.exit(0);
})().catch((error) => {
  console.error(error);
  process.exit(1);
});
